  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider        = \"prisma-client-js\"\n  output          = \"client\"\n  previewFeatures = [\"typedSql\"]\n}\n\ndatasource db {\n  provider = \"mysql\"\n  // NOTE: When using mysql or sqlserver, uncomment the @db.Text annotations in model Account below\n  // Further reading:\n  // https://next-auth.js.org/adapters/prisma#create-the-prisma-schema\n  // https://www.prisma.io/docs/reference/api-reference/prisma-schema-reference#string\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel Post {\n  id          Int      @id @default(autoincrement())\n  name        String\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n  createdBy   User     @relation(fields: [createdById], references: [id])\n  createdById String\n\n  @@index([name])\n}\n\n// Necessary for Next auth\nmodel Account {\n  id                       String  @id @default(cuid())\n  userId                   String\n  type                     String\n  provider                 String\n  providerAccountId        String\n  refresh_token            String? @db.Text\n  access_token             String? // @db.Text\n  expires_at               Int?\n  token_type               String?\n  scope                    String?\n  id_token                 String? // @db.Text\n  session_state            String?\n  user                     User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  refresh_token_expires_in Int?\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel User {\n  id            String       @id @default(cuid())\n  name          String?\n  email         String?      @unique\n  emailVerified DateTime?\n  image         String?\n  accounts      Account[]\n  sessions      Session[]\n  posts         Post[]\n  decks         Deck[]       @relation(\"DeckOwner\")\n  flashcards    FlashCard[]  @relation(\"FlashOwner\")\n  accesses      DeckAccess[]\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\nmodel Deck {\n  id            String          @id @default(dbgenerated(\"(uuid())\")) @db.Char(36)\n  name          String          @db.Text\n  owner         User            @relation(\"DeckOwner\", fields: [ownerId], references: [id])\n  ownerId       String          @db.Char(36) // Changed to string to match User.id\n  public        AccessLevel     @default(PRIVATE) // Using enum instead of TinyInt\n  accesses      DeckAccess[]\n  flashcards    FlashCard[]     @relation(\"DeckFlashCards\")\n  deckflashcard DeckFlashCard[]\n\n  @@index([ownerId])\n}\n\nmodel FlashCard {\n  id            String          @id @default(dbgenerated(\"(uuid())\")) @db.Char(36)\n  owner         User            @relation(\"FlashOwner\", fields: [ownerId], references: [id])\n  ownerId       String          @db.Char(36) // Changed to string to match User.id\n  title         String          @db.Text\n  content       String          @db.Text\n  decks         Deck[]          @relation(\"DeckFlashCards\")\n  deckflashcard DeckFlashCard[]\n}\n\nmodel DeckFlashCard {\n  deck      Deck              @relation(fields: [deckId], references: [id])\n  deckId    String            @db.Char(36)\n  flash     FlashCard         @relation(fields: [flashId], references: [id])\n  flashId   String            @db.Char(36)\n  progress  FlashCardProgress @default(BEGIN) // Per-deck progress tracking\n  createdAt DateTime          @default(now())\n\n  @@id([deckId, flashId])\n  @@index([deckId])\n  @@index([flashId])\n}\n\nmodel DeckAccess {\n  deck      Deck        @relation(fields: [deckId], references: [id])\n  deckId    String      @db.Char(36)\n  user      User        @relation(fields: [userId], references: [id])\n  userId    String      @db.Char(36)\n  level     AccessLevel @default(VIEW)\n  createdAt DateTime    @default(now())\n\n  @@id([deckId, userId]) // Composite key instead of separate UUID\n  @@index([deckId])\n  @@index([userId])\n}\n\nenum AccessLevel {\n  PRIVATE // 0 - For Deck.public\n  VIEW // 1\n  EDIT // 2\n  ADMIN // 3\n}\n\nenum FlashCardProgress {\n  MASTERY\n  INTERM\n  BEGIN\n}\n",
